import { fromOpenai } from 'instructor';
import { OpenAI } from 'openai';
import { z } from 'zod';

const SourceFact = z.object({
  claim: z.string(),
  sourceUrl: z.string().url(),
  excerpt: z.string().min(50),
  recencyDays: z.number().min(0),
  confidence: z.number().min(0).max(1)
});

const client = fromOpenai(new OpenAI());
const facts = await client.chat.completions.create({
  model: 'gpt-4o',
  responseModel: z.array(SourceFact),
  messages: [{ role: 'user', content: 'Extract from search results...' }]
});

console.log(facts.map(f => `${f.claim} (${f.recencyDays}d)`));

