import { verify } from 'vex-sdk';
import { fromOpenai } from 'instructor';
import OpenAI from 'openai';

const researchPipeline = verify(
  async (query: string) => {
    const client = fromOpenai(new OpenAI());

    const facts = await client.chat.completions.create({
      model: 'gpt-4o',
      responseModel: SourceFactArray,
      messages: [{ role: 'user', content: query }],
      criteria: ['source_verification', 'claim_accuracy']
    });

    return facts;
  },
  { criteria: ['source_verification', 'recency_checks', 'bias_detection'] }
);

// Usage
const results = await researchPipeline('Latest AI benchmarks');
